# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

from flask import Flask, request, jsonify
from collections import defaultdict, Counter
import threading
import numpy as np
from sklearn.ensemble import RandomForestClassifier

app = Flask(__name__)

# In-memory data store
image_labels = defaultdict(list)
lock = threading.Lock()
classifier = RandomForestClassifier()

# API route to accept image labels
@app.route('/submit_label', methods=['POST'])
def submit_label():
    data = request.json
    image_id = data['image_id']
    label = data['label']
    with lock:
        image_labels[image_id].append(label)
    return jsonify({'message': 'Label submitted successfully'}), 200

# Function to aggregate labels using majority voting
def aggregate_labels():
    aggregated_labels = {}
    with lock:
        for image_id, labels in image_labels.items():
            label_counter = Counter(labels)
            majority_label = label_counter.most_common(1)[0][0]
            aggregated_labels[image_id] = majority_label
    return aggregated_labels

# Train on aggregated data
@app.route('/train_model', methods=['POST'])
def train_model():
    data = request.json
    feature_vectors = np.array(data['feature_vectors'])
    
    # Aggregate labels
    aggregated_labels = aggregate_labels()
    
    # Prepare training data
    y_train = [aggregated_labels[image_id] for image_id in sorted(aggregated_labels)]
    
    # Check if feature_vectors align with labels
    if len(feature_vectors) != len(y_train):
        return jsonify({'error': 'Mismatch between features and labels'}), 400
    
    # Train the model
    with lock:
        classifier.fit(feature_vectors, y_train)
    
    return jsonify({'message': 'Model trained successfully'}), 200

if __name__ == '__main__':
    app.run(debug=True)